{
  "title": "संग्रहण लागत विश्लेषण",
  "group": "लागत अनुकूलन",
  "options": [
    {
      "text": "सभी डेटा के लिए S3 मानक",
      "hint": "दैनिक पहुंच के लिए अच्छा, लेकिन अधिक लागत वाला"
    },
    {
      "text": "हमेशा सस्ते संग्रहण का उपयोग करें",
      "hint": "पुनर्प्राप्ति लागत को ध्यान में रखें"
    },
    {
      "text": "पहुंच पैटर्न के आधार पर संग्रहण वर्गों का मिश्रण करें",
      "hint": "अनुकूलित संतुलन के लिए सबसे अच्छा"
    },
    {
      "text": "सबकुछ Glacier में संग्रहित करें",
      "hint": "अत्यधिक लंबे समय तक अनुपलब्ध डेटा के लिए उपयुक्त"
    }
  ],
  "questionProse": [
    "1 पीबी डेटा के लिए सबसे लागत-प्रभावी दृष्टिकोण क्या है जिसमें 20% दैनिक, 30% मासिक और 50% वार्षिक पहुंच है?"
  ],
  "explanationProse": [
    "अनुकूलित संग्रहण रणनीति:\n    - दैनिक पहुंच के लिए 20% S3 मानक में\n    - मासिक पहुंच के लिए 30% S3 मानक-IA में\n    - वार्षिक पहुंच के लिए 50% Glacier में\n\n    यह दृष्टिकोण लागत को अनुकूलित करते हुए उपयुक्त पहुंच पैटर्न बनाए रखता है।\n\n    लागत विचाराधीन:\n    - जीबी प्रति संग्रहण मूल्य\n    - पुनर्प्राप्ति लागत\n    - पहुंच पैटर्न\n    - स्थानांतरण लागत"
  ]
}
